# Category: graphql_security

import graphene
from flask import Flask, jsonify
from flask_graphql import GraphQLView

app = Flask(__name__)
schema = graphene.Schema(query=Query)
view = GraphQLView.as_view('graphql', schema=schema, graphiql=True)
app.add_url_rule('/graphql', view_func=view)

class Query:
    products = graphene.List(ProductType)
    categories = graphene.List(CategoryType)
    reviews = graphene.List(ReviewType)

class ProductType:
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()

class CategoryType:
    id = graphene.ID()
    name = graphene.String()

class ReviewType:
    id = graphene.ID()
    product_id = graphene.ID()
    user_id = graphene.ID()
    rating = graphene.Int()
    comment = graphene.String()

@app.route('/products')
def get_products():
    products = [
        {'id': 1, 'name': 'Product 1', 'description': 'This is product 1', 'price': 10.99},
        {'id': 2, 'name': 'Product 2', 'description': 'This is product 2', 'price': 15.99},
        {'id': 3, 'name': 'Product 3', 'description': 'This is product 3', 'price': 20.99}
    ]
    return jsonify(products)

@app.route('/categories')
def get_categories():
    categories = [
        {'id': 1, 'name': 'Category 1'},
        {'id': 2, 'name': 'Category 2'},
        {'id': 3, 'name': 'Category 3'}
    ]
    return jsonify(categories)

@app.route('/reviews')
def get_reviews():
    reviews = [
        {'id': 1, 'product_id': 1, 'user_id': 1, 'rating': 5, 'comment': 'This is a great product!'},
        {'id': 2, 'product_id': 2, 'user_id': 2, 'rating': 4, 'comment': 'I like this product, but...'},
        {'id': 3, 'product_id': 3, 'user_id': 3, 'rating': 5, 'comment': 'This is the best product ever!'}
    ]
    return jsonify(reviews)